mapper.sql:
from facility_check_hstry fch inner join facility f on fch.facility_no = f.facility_no left outer join partner p on fch.partner_no = p.partner_no and p.apt_cmplex_no = f.apt_cmplex_no inner join mgmt_office mo on mo.apt_cmplex_no = f.apt_cmplex_no left join common_code fac_ty on fac_ty.group_code_no = 'FACILITY_TY' and fac_ty.code_no_cd = f.facility_ty_cd and fac_ty.use_yn = 'Y' left join common_code chk_ty on chk_ty.group_code_no = 'CHECK_TY' and chk_ty.code_no_cd = fch.chk_ty_cd and chk_ty.use_yn = 'Y' left join common_code chk_ctgry on chk_ctgry.group_code_no = 'CHECK_CTGRY' and chk_ctgry.code_no_cd = fch.chk_ctgry_cd and chk_ctgry.use_yn = 'Y' left join common_code chk_stts on chk_stts.group_code_no = 'CHECK_STTS' and chk_stts.code_no_cd = fch.chk_stts_cd and chk_stts.use_yn = 'Y' where mo.mgmt_ofc_no = #{searchVO.mgmtOfcNo}
and fch.facility_no = #{searchVO.facilityNo}
and fch.partner_no = #{searchVO.partnerNo}
and ( upper(fch.fac_chk_hstry_no) like '%' || upper(#{searchWord}) || '%' or upper(fch.chk_flow_no) like '%' || upper(#{searchWord}) || '%' or upper(fch.facility_no) like '%' || upper(#{searchWord}) || '%' or upper(f.facility_nm) like '%' || upper(#{searchWord}) || '%' or upper(p.partner_nm) like '%' || upper(#{searchWord}) || '%' or ('자체점검' like '%' || #{searchWord} || '%' and fch.partner_no is null) )
and fch.chk_ctgry_cd = #{searchVO.chkCtgryCd}
and fch.chk_ty_cd = #{searchVO.chkTyCd}
and fch.chk_stts_cd = #{searchVO.chkSttsCd}
and nvl(fch.use_restrict_yn, 'N') = #{searchVO.useRestrictYn}
and nvl(fch.use_restrict_yn, 'N') = 'Y' and sysdate >= fch.use_restrict_bgng_dt and sysdate < fch.use_restrict_end_dt
and nvl(fch.use_restrict_yn, 'N') = 'Y' and fch.use_restrict_bgng_dt > sysdate
and nvl(fch.use_restrict_yn, 'N') = 'Y' and fch.use_restrict_end_dt <= sysdate
and nvl(fch.use_restrict_yn, 'N') = 'N'
and fch.chk_dt >= to_date(#{searchVO.chkStartDt}, 'yyyy-mm-dd')
and fch.chk_dt < to_date(#{searchVO.chkEndDt}, 'yyyy-mm-dd') + 1

mapper.insert:

    select 'FCH' || lpad(seq_facility_check_hstry.nextval, 4, '0')
    from dual


insert into facility_check_hstry (
fac_chk_hstry_no
, cont_no
, facility_no
, partner_no
, chk_flow_no
, chk_dt
, chk_stts_cd
, chk_cn
, rmk
, use_restrict_yn
, use_restrict_bgng_dt
, use_restrict_end_dt
, reg_dt
, chk_ctgry_cd
, chk_ty_cd
) values (
#{facChkHstryNo}
, #{contNo}
, #{facilityNo}
, #{partnerNo}
, #{chkFlowNo}
, to_date(#{chkDt}, 'yyyy-mm-dd')
, #{chkSttsCd}
, #{chkCn}
, #{rmk}
, nvl(#{useRestrictYn}, 'N')
, case when #{useRestrictYn} = 'Y' and #{useRestrictBgngDt} is not null then to_date(#{useRestrictBgngDt}, 'yyyy-mm-dd"T"hh24:mi') end
, case when #{useRestrictYn} = 'Y' and #{useRestrictEndDt} is not null then to_date(#{useRestrictEndDt}, 'yyyy-mm-dd"T"hh24:mi') end
, sysdate
, #{chkCtgryCd}
, #{chkTyCd}
)

mapper.update:
update facility_check_hstry
set facility_no = #{facilityNo}
  , cont_no = #{contNo}
  , partner_no = #{partnerNo}
  , chk_flow_no = #{chkFlowNo}
  , chk_dt = to_date(#{chkDt}, 'yyyy-mm-dd')
  , chk_stts_cd = #{chkSttsCd}
  , chk_cn = #{chkCn}
  , rmk = #{rmk}
  , use_restrict_yn = nvl(#{useRestrictYn}, 'N')
  , use_restrict_bgng_dt = case when #{useRestrictYn} = 'Y' and #{useRestrictBgngDt} is not null then to_date(#{useRestrictBgngDt}, 'yyyy-mm-dd"T"hh24:mi') end
  , use_restrict_end_dt = case when #{useRestrictYn} = 'Y' and #{useRestrictEndDt} is not null then to_date(#{useRestrictEndDt}, 'yyyy-mm-dd"T"hh24:mi') end
  , mdf_dt = sysdate
  , chk_ctgry_cd = #{chkCtgryCd}
  , chk_ty_cd = #{chkTyCd}
where fac_chk_hstry_no = #{facChkHstryNo}

mapper.select:
select f.facility_no , f.facility_nm , f.facility_ty_cd , fac_ty.code_name as facility_ty_nm , f.dong_no , au.dong_nm , f.loc_cn , f.use_yn , to_char(f.instl_dt, 'yyyy-mm-dd') as instl_dt from facility f inner join mgmt_office mo on mo.apt_cmplex_no = f.apt_cmplex_no left join ( select apt_cmplex_no , dong_no , max(dong_nm) as dong_nm from apt_unit group by apt_cmplex_no, dong_no ) au on au.apt_cmplex_no = f.apt_cmplex_no and au.dong_no = f.dong_no left join common_code fac_ty on fac_ty.group_code_no = 'FACILITY_TY' and fac_ty.code_no_cd = f.facility_ty_cd and fac_ty.use_yn = 'Y' where mo.mgmt_ofc_no = #{mgmtOfcNo}
and f.facility_ty_cd = #{facilityTyCd}
and f.dong_no = #{dongNo}
and f.use_yn = #{facilityUseYn}
and upper(f.loc_cn) like '%' || upper(#{facilityLocCn}) || '%'
and ( upper(f.facility_no) like '%' || upper(#{facilitySearchWord}) || '%' or upper(f.facility_nm) like '%' || upper(#{facilitySearchWord}) || '%' or upper(f.loc_cn) like '%' || upper(#{facilitySearchWord}) || '%' or upper(fac_ty.code_name) like '%' || upper(#{facilitySearchWord}) || '%' or upper(f.dong_no) like '%' || upper(#{facilitySearchWord}) || '%' or upper(au.dong_nm) like '%' || upper(#{facilitySearchWord}) || '%' )
order by f.facility_nm, f.facility_no

select p.partner_no , p.partner_nm , p.biz_ty_nm , p.bizrno , p.use_yn , p.pic_nm , p.pic_telno , p.pic_email from partner p inner join mgmt_office mo on mo.apt_cmplex_no = p.apt_cmplex_no where mo.mgmt_ofc_no = #{mgmtOfcNo}
and p.biz_ty_nm = #{bizTyNm}
and p.use_yn = #{partnerUseYn}
and upper(p.pic_nm) like '%' || upper(#{picNm}) || '%'
and ( upper(p.partner_no) like '%' || upper(#{partnerSearchWord}) || '%' or upper(p.partner_nm) like '%' || upper(#{partnerSearchWord}) || '%' or upper(p.bizrno) like '%' || upper(#{partnerSearchWord}) || '%' or upper(p.biz_ty_nm) like '%' || upper(#{partnerSearchWord}) || '%' or upper(p.pic_nm) like '%' || upper(#{partnerSearchWord}) || '%' or upper(p.pic_telno) like '%' || upper(#{partnerSearchWord}) || '%' )
order by p.use_yn desc, p.partner_nm, p.partner_no

select fc.cont_no as "contNo" , fc.cont_nm as "contNm" , fc.cont_ty_cd as "contTyCd" , fc.cont_target_cd as "contTargetCd" , fc.cont_stts_cd as "contSttsCd" , to_char(fc.cont_bgng_dt, 'yyyy.mm.dd') as "contBgngDt" , to_char(fc.cont_end_dt, 'yyyy.mm.dd') as "contEndDt" from facility_contract fc inner join facility_contract_target fct on fct.cont_no = fc.cont_no inner join facility f on f.facility_no = fct.facility_no inner join mgmt_office mo on mo.apt_cmplex_no = f.apt_cmplex_no where mo.mgmt_ofc_no = #{mgmtOfcNo} and fc.partner_no = #{partnerNo}
and fct.facility_no = #{facilityNo}
and fc.cont_stts_cd = 'ACTIVE' order by "contBgngDt" desc

select fc.cont_no as "contNo" , fc.cont_nm as "contNm" , fc.cont_ty_cd as "contTyCd" , fc.cont_target_cd as "contTargetCd" , fc.cont_stts_cd as "contSttsCd" , fc.partner_no as "partnerNo" , p.partner_nm as "partnerNm" , p.biz_ty_nm as "bizTyNm" , p.pic_nm as "picNm" , p.pic_telno as "picTelno" , p.pic_email as "picEmail" , to_char(fc.cont_bgng_dt, 'yyyy.mm.dd') as "contBgngDt" , to_char(fc.cont_end_dt, 'yyyy.mm.dd') as "contEndDt" from facility_contract fc inner join facility_contract_target fct on fct.cont_no = fc.cont_no inner join partner p on p.partner_no = fc.partner_no inner join mgmt_office mo on mo.apt_cmplex_no = p.apt_cmplex_no where mo.mgmt_ofc_no = #{mgmtOfcNo}
and fct.facility_no = #{facilityNo}
and fc.cont_target_cd = 'FACILITY'
and fc.cont_ty_cd not in ('INSTALL', 'METER')
and fc.cont_stts_cd = 'ACTIVE' order by nvl(fc.cont_end_dt, fc.cont_bgng_dt) desc, fc.cont_no desc
